import{c as a,Q as r,j as e,m as n}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"大语言模型（LLM）","description":"","frontmatter":{},"headers":[],"relativePath":"docs/llm.md","filePath":"docs/llm.md"}'),o={name:"docs/llm.md"};function l(i,t,s,d,h,g){return r(),e("div",null,[...t[0]||(t[0]=[n(`<h1 id="大语言模型-llm" tabindex="-1">大语言模型（LLM） <a class="header-anchor" href="#大语言模型-llm" aria-label="Permalink to &quot;大语言模型（LLM）&quot;">​</a></h1><p>大语言模型（Large Language Model，LLM）是一类基于深度学习的自然语言处理模型，通过在海量文本上进行预训练，学习语言的统计规律、世界知识与推理模式，从而能够完成文本生成、理解、翻译、摘要、问答等多种任务。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="什么是-llm" tabindex="-1">什么是 LLM <a class="header-anchor" href="#什么是-llm" aria-label="Permalink to &quot;什么是 LLM&quot;">​</a></h3><p>LLM 通常指参数量达到数十亿乃至数千亿级别的语言模型。与早期基于规则或浅层统计的方法不同，LLM 以 <strong>自回归</strong> 或 <strong>掩码语言建模</strong> 为目标，在 Transformer 架构上规模化训练，具备较强的泛化能力与涌现能力（Emergent Abilities）。</p><h3 id="关键术语" tabindex="-1">关键术语 <a class="header-anchor" href="#关键术语" aria-label="Permalink to &quot;关键术语&quot;">​</a></h3><table tabindex="0"><thead><tr><th>术语</th><th>说明</th></tr></thead><tbody><tr><td><strong>Token</strong></td><td>模型处理的最小文本单元，可能是字、词或子词（BPE/SentencePiece）</td></tr><tr><td><strong>上下文窗口（Context Window）</strong></td><td>单次推理可容纳的最大 Token 数，决定模型能“看到”多长的历史</td></tr><tr><td><strong>温度（Temperature）</strong></td><td>控制采样随机性，越高输出越多样，越低越确定</td></tr><tr><td><strong>Top-p / Top-k</strong></td><td>限制采样候选集，在多样性与质量之间权衡</td></tr><tr><td><strong>幻觉（Hallucination）</strong></td><td>模型生成看似合理但事实错误的内容</td></tr><tr><td><strong>对齐（Alignment）</strong></td><td>使模型输出符合人类价值观与指令意图的训练过程</td></tr></tbody></table><h2 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-label="Permalink to &quot;技术架构&quot;">​</a></h2><h3 id="transformer-基础" tabindex="-1">Transformer 基础 <a class="header-anchor" href="#transformer-基础" aria-label="Permalink to &quot;Transformer 基础&quot;">​</a></h3><p>现代 LLM 几乎均基于 <strong>Transformer</strong>（Vaswani et al., 2017）：</p><ul><li><strong>自注意力（Self-Attention）</strong>：让每个 Token 关注序列中其他位置，捕获长距离依赖</li><li><strong>多头注意力（Multi-Head Attention）</strong>：并行学习多种关系模式</li><li><strong>位置编码</strong>：弥补注意力机制本身不包含顺序信息的问题（绝对/相对/RoPE 等）</li><li><strong>前馈网络（FFN）</strong>：对每个位置做非线性变换</li></ul><p>常见变体包括 <strong>仅解码器（Decoder-only）</strong>、<strong>编码器-解码器（Encoder-Decoder）</strong> 等；GPT 系列、LLaMA、Qwen 等主流开源模型多采用 Decoder-only。</p><h3 id="模型规模与能力" tabindex="-1">模型规模与能力 <a class="header-anchor" href="#模型规模与能力" aria-label="Permalink to &quot;模型规模与能力&quot;">​</a></h3><p>参数量、训练数据量与算力通常遵循 <strong>缩放定律（Scaling Laws）</strong>：在一定范围内，模型越大、数据越多，下游任务表现越好，并可能出现小模型不具备的能力（如复杂推理、代码生成）。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>预训练数据 → Tokenizer → Transformer 堆叠 → 语言建模头 → 下一个 Token 预测</span></span></code></pre></div><h2 id="训练流程" tabindex="-1">训练流程 <a class="header-anchor" href="#训练流程" aria-label="Permalink to &quot;训练流程&quot;">​</a></h2><p>LLM 的完整生命周期通常分为以下阶段：</p><h3 id="_1-预训练-pre-training" tabindex="-1">1. 预训练（Pre-training） <a class="header-anchor" href="#_1-预训练-pre-training" aria-label="Permalink to &quot;1. 预训练（Pre-training）&quot;">​</a></h3><p>在大规模无标注语料（网页、书籍、代码等）上进行 <strong>自监督学习</strong>，目标多为：</p><ul><li><strong>因果语言建模（CLM）</strong>：根据前文预测下一个 Token（GPT 类）</li><li><strong>掩码语言建模（MLM）</strong>：预测被遮盖的 Token（BERT 类，多用于理解任务）</li></ul><p>预训练使模型掌握语法、常识与一定推理能力，但未必善于遵循用户指令。</p><h3 id="_2-监督微调-sft" tabindex="-1">2. 监督微调（SFT） <a class="header-anchor" href="#_2-监督微调-sft" aria-label="Permalink to &quot;2. 监督微调（SFT）&quot;">​</a></h3><p>使用高质量的「指令 - 回答」对进行有监督微调，使模型学会 <strong>按指令完成任务</strong>（对话、写作、分析等）。</p><h3 id="_3-人类反馈强化学习-rlhf-rlaif" tabindex="-1">3. 人类反馈强化学习（RLHF / RLAIF） <a class="header-anchor" href="#_3-人类反馈强化学习-rlhf-rlaif" aria-label="Permalink to &quot;3. 人类反馈强化学习（RLHF / RLAIF）&quot;">​</a></h3><p>通过人类或 AI 对多个回答排序，训练 <strong>奖励模型（Reward Model）</strong>，再用 PPO、DPO、GRPO 等方法优化策略，使输出更安全、有用、诚实。</p><h3 id="_4-持续迭代" tabindex="-1">4. 持续迭代 <a class="header-anchor" href="#_4-持续迭代" aria-label="Permalink to &quot;4. 持续迭代&quot;">​</a></h3><p>包括领域微调、量化部署、检索增强（RAG）、工具调用（Function Calling / Agent）等工程化扩展。</p><div class="tip custom-block"><p class="custom-block-title">训练与推理的区别</p><p>训练需要反向传播与大量 GPU 显存；推理（Inference）仅做前向计算，关注延迟、吞吐与成本，常采用量化（INT8/INT4）、KV Cache、批处理等优化。</p></div><h2 id="典型应用场景" tabindex="-1">典型应用场景 <a class="header-anchor" href="#典型应用场景" aria-label="Permalink to &quot;典型应用场景&quot;">​</a></h2><ul><li><strong>对话与助手</strong>：智能客服、个人助理、多轮问答</li><li><strong>内容创作</strong>：文章、营销文案、剧本、邮件</li><li><strong>代码</strong>：补全、解释、重构、单元测试生成（Copilot、Cursor 等）</li><li><strong>知识工作</strong>：摘要、翻译、信息抽取、报告分析</li><li><strong>RAG 系统</strong>：结合向量数据库，用私有文档增强回答准确性</li><li><strong>Agent</strong>：结合规划、记忆与工具调用，完成多步骤复杂任务</li></ul><h2 id="主流模型概览" tabindex="-1">主流模型概览 <a class="header-anchor" href="#主流模型概览" aria-label="Permalink to &quot;主流模型概览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>代表</th><th>特点</th></tr></thead><tbody><tr><td>闭源 API</td><td>GPT-4o、Claude、Gemini</td><td>能力强、易用，依赖云端 API</td></tr><tr><td>开源通用</td><td>LLaMA、Qwen、Mistral、DeepSeek</td><td>可本地部署、可微调</td></tr><tr><td>代码专用</td><td>CodeLlama、StarCoder、DeepSeek-Coder</td><td>代码理解与生成优化</td></tr><tr><td>多模态</td><td>GPT-4V、LLaVA、Qwen-VL</td><td>同时处理文本与图像</td></tr></tbody></table><p>选型时需综合考虑：<strong>能力、成本、延迟、隐私合规、是否支持中文与领域知识</strong>。</p><h2 id="使用-llm-的最佳实践" tabindex="-1">使用 LLM 的最佳实践 <a class="header-anchor" href="#使用-llm-的最佳实践" aria-label="Permalink to &quot;使用 LLM 的最佳实践&quot;">​</a></h2><h3 id="提示工程-prompt-engineering" tabindex="-1">提示工程（Prompt Engineering） <a class="header-anchor" href="#提示工程-prompt-engineering" aria-label="Permalink to &quot;提示工程（Prompt Engineering）&quot;">​</a></h3><ul><li>角色与任务描述清晰（System / User 分工）</li><li>提供示例（Few-shot）或输出格式约束（JSON、Markdown）</li><li>复杂任务拆分为多步（Chain-of-Thought、ReAct）</li><li>对长文档使用分块、摘要或 RAG，避免超出上下文窗口</li></ul><h3 id="控制输出质量" tabindex="-1">控制输出质量 <a class="header-anchor" href="#控制输出质量" aria-label="Permalink to &quot;控制输出质量&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>低温度（0～0.3）  → 事实性、格式稳定的任务</span></span>
<span class="line"><span>中温度（0.5～0.8）→ 通用对话与创作</span></span>
<span class="line"><span>高温度（&gt;1）      → 创意发散，但幻觉风险上升</span></span></code></pre></div><h3 id="安全与合规" tabindex="-1">安全与合规 <a class="header-anchor" href="#安全与合规" aria-label="Permalink to &quot;安全与合规&quot;">​</a></h3><ul><li>对用户输入做过滤，防止提示注入（Prompt Injection）</li><li>敏感数据勿直接送入不可信第三方 API</li><li>关键业务场景需人工审核或与传统系统交叉验证</li></ul><h2 id="局限与挑战" tabindex="-1">局限与挑战 <a class="header-anchor" href="#局限与挑战" aria-label="Permalink to &quot;局限与挑战&quot;">​</a></h2><ul><li><strong>知识截止</strong>：预训练数据有时间边界，实时信息需 RAG 或工具</li><li><strong>幻觉</strong>：可能编造引用、数据或逻辑</li><li><strong>推理成本</strong>：长上下文与高并发带来算力与费用压力</li><li><strong>偏见与安全</strong>：训练数据中的偏见可能被放大</li><li><strong>可解释性</strong>：难以精确说明某一回答的内部依据</li></ul><h2 id="生态与工具" tabindex="-1">生态与工具 <a class="header-anchor" href="#生态与工具" aria-label="Permalink to &quot;生态与工具&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>常见工具/框架</th></tr></thead><tbody><tr><td>推理服务</td><td>vLLM、TGI、Ollama、llama.cpp</td></tr><tr><td>应用框架</td><td>LangChain、LlamaIndex、Semantic Kernel</td></tr><tr><td>微调</td><td>Hugging Face Transformers、PEFT/LoRA、Axolotl</td></tr><tr><td>评估</td><td>OpenCompass、lm-evaluation-harness</td></tr><tr><td>向量检索</td><td>Milvus、Qdrant、pgvector、Elasticsearch</td></tr></tbody></table><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><strong>论文</strong>：Attention Is All You Need；GPT-3；InstructGPT；LoRA</li><li><strong>方向</strong>：多模态大模型、MoE 架构、长上下文（128K+）、端侧小模型、Agent 与工具学习</li></ul><hr><blockquote><p>本文档为 AI 技术知识库的一部分，概述 LLM 的定义、原理、训练与应用。后续可补充具体模型的部署教程、RAG 实践与评测方法。</p></blockquote>`,48)])])}const u=a(o,[["render",l]]);export{p as __pageData,u as default};
